require('dotenv').config();
const { Pool } = require('pg');

// Prefer DATABASE_URL (Heroku Postgres addon / staging) so `npm run seed` targets
// the addon DB. Falls back to PG* vars (local .env / prod). NOTE: this script
// TRUNCATEs `shipments` — only run it against a disposable/staging database.
const pool = process.env.DATABASE_URL
  ? new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } })
  : new Pool({
      host: process.env.PGHOST,
      database: process.env.PGDATABASE,
      user: process.env.PGUSER,
      password: process.env.PGPASSWORD,
      port: process.env.PGPORT || 5432,
      ssl: { rejectUnauthorized: false }
    });

