const createTableQuery = `
CREATE TABLE IF NOT EXISTS shipments (
    id SERIAL PRIMARY KEY,
    no INTEGER,
    cargo_type VARCHAR(50),
    consignee VARCHAR(255),
    project_name VARCHAR(255),
    product VARCHAR(100),
    quantity_mt NUMERIC,
    bl_number VARCHAR(100),
    shipping_line VARCHAR(255),
    vessel_name VARCHAR(255),
    voyage_number VARCHAR(100),
    pol VARCHAR(100),
    pod VARCHAR(100),
    shipment_route VARCHAR(50),
    etd DATE,
    eta DATE,
    shipment_type VARCHAR(50),
    est_sailing_days NUMERIC,
    actual_sailing_days NUMERIC,
    pib_billing DATE,
    bpn DATE,
    spjm DATE,
    behandle DATE,
    sppb DATE,
    clearance_days NUMERIC,
    start_unloading DATE,
    finish_unloading DATE,
    unloading_days NUMERIC,
    cargo_status VARCHAR(50),
    start_delivery DATE,
    enter_warehouse DATE,
    delivery_days NUMERIC,
    vendor_trucking VARCHAR(255),
    warehouse_location VARCHAR(255),
    status VARCHAR(50),
    remarks TEXT,
    year INTEGER,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
`;

async function seedData() {
  const client = await pool.connect();
  try {
    console.log("Creating table if not exists...");
    await client.query(createTableQuery);

    console.log("Truncating existing data (optional, ensures clean slate)...");
    await client.query('TRUNCATE TABLE shipments RESTART IDENTITY;');

    console.log(`Inserting ${D.length} records...`);
    for (const data of D) {
      const keys = Object.keys(data);
      // Map empty strings to null for PostgreSQL strict typing
      const values = Object.values(data).map(v => v === '' ? null : v);
      const placeholders = keys.map((_, i) => `$${i + 1}`).join(', ');
      
      const query = `INSERT INTO shipments (${keys.join(', ')}) VALUES (${placeholders})`;
      await client.query(query, values);
    }
    
    console.log("✅ Seeding completed successfully.");
  } catch (error) {
    console.error("❌ Seeding failed:", error);
  } finally {
    client.release();
    pool.end();
  }
}

seedData();